from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(path):
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'error': 'Authorization header is missing'}), 401

    try:
        # Assuming the token is in the format "Bearer <token>"
        token = token.split()[1]
        user_claims = jwt.decode(token, options={"verify_signature": False})
    except Exception as e:
        return jsonify({'error': 'Invalid token', 'message': str(e)}), 401

    # Forward the user claims to the backend service
    # Here you would typically make a request to the backend service
    # For demonstration, we will just return the user claims
    return jsonify({'user_claims': user_claims, 'path': path})

if __name__ == '__main__':
    app.run(debug=True)